     * Compare two URLs by scheme + host + effective port.
     */
    private function sameOrigin(string $a, string $b): bool
    {
        $pa = parse_url($a);
        $pb = parse_url($b);
        if ($pa === false || $pb === false) {
            return false;
        }
        if (strtolower($pa['scheme'] ?? '') !== strtolower($pb['scheme'] ?? '')) {
            return false;
        }
        if (strtolower($pa['host'] ?? '') !== strtolower($pb['host'] ?? '')) {
            return false;
        }
        $portA = $pa['port'] ?? (strtolower($pa['scheme'] ?? '') === 'https' ? 443 : 80);
        $portB = $pb['port'] ?? (strtolower($pb['scheme'] ?? '') === 'https' ? 443 : 80);

        return $portA === $portB;
    }

    /**
     * Return a comma-separated list of supported content encodings.
     *
     * @return string supported encoding names
     */
    private function getSupportedEncodings(): string
    {
        $encodings = ['gzip', 'deflate'];
        if (function_exists('brotli_uncompress')) {
            $encodings[] = 'br';
        }
        if (function_exists('zstd_uncompress')) {
            $encodings[] = 'zstd';
        }

        return implode(', ', $encodings);
    }

    /**
     * Decompress a response body based on the Content-Encoding header value.
     *
     * @param string $body     the raw response body
     * @param string $encoding the Content-Encoding header value
     * @return string the decompressed body
     */
    private function decompressBody(string $body, string $encoding): string
    {
        if ($body === '') {
            return $body;
        }

        return match (strtolower($encoding)) {
            'gzip', 'x-gzip' => gzdecode($body)
                ?: throw new \RuntimeException('Failed to gzip-decompress response body'),
            'deflate' => gzuncompress($body)
                ?: throw new \RuntimeException('Failed to deflate-decompress response body'),
            'br' => function_exists('brotli_uncompress')
                ? (brotli_uncompress($body)
                    ?: throw new \RuntimeException('Failed to brotli-decompress response body'))
                : $body,
            'zstd' => function_exists('zstd_uncompress')
                ? (zstd_uncompress($body)
                    ?: throw new \RuntimeException('Failed to zstd-decompress response body'))
                : $body,
            default => $body,
        };
    }

    /**
     * Resets the underlying Symfony HTTP client, closing any open
     * connections and clearing pooled state. Safe to call multiple times.
     * Symfony's `ResetInterface` is implemented by both CurlHttpClient and
     * NativeHttpClient; for clients that don't implement it this is a no-op.
     */
    public function close(): void
    {
        if ($this->client instanceof \Symfony\Contracts\Service\ResetInterface) {
            $this->client->reset();
        }
        /* Gap T-D4: flip the closed flag so a subsequent sendRequest()
         * surfaces an SDK-typed ApiException. Idempotent — safe to call
         * close() repeatedly. */
        $this->closed = true;
    }

    /**
     * Rejects multipart filenames that would allow Content-Disposition header
     * injection or smuggling. Throws InvalidArgumentException when the
     * filename contains CR, LF, or NUL characters.
     *
     * @internal Not part of the public API; exposed only for SDK-internal use
     *           and direct unit testing. May change or be removed in any
     *           release without notice.
     *
     * @param string|null $filename the filename to validate
     * @throws \InvalidArgumentException when the filename contains CR/LF/NUL
     */
    public static function validateMultipartFilename(?string $filename): void
    {
        if ($filename === null) {
            return;
        }
        if (preg_match("/[\r\n\0]/", $filename) === 1) {
            throw new \InvalidArgumentException(
                'multipart filename must not contain CR, LF, or NUL characters'
            );
        }
    }

    /**
     * Validates a multipart form field NAME. CR/LF/NUL in the name would
     * inject a forged header line into the `Content-Disposition: form-data;
     * name="..."` segment. Symfony's FormDataPart trusts caller-supplied
     * keys verbatim so we guard before handing them over (W-new-2).
     *
     * @param string $name the field name to validate
     * @throws \InvalidArgumentException when the name contains CR/LF/NUL
     */
    private function validateMultipartFieldName(string $name): void
    {
        if (preg_match("/[\r\n\0]/", $name) === 1) {
            throw new \InvalidArgumentException(
                'multipart field name must not contain CR, LF, or NUL characters'
            );
        }
    }

    /**
     * Builds the `filename=...` directive for a multipart Content-Disposition
     * header. For ASCII-only filenames emits a quote/backslash-escaped
     * `filename="..."`. For non-ASCII filenames additionally emits an RFC 5987
     * `filename*=UTF-8''<percent-encoded>` parameter alongside an ASCII
     * fallback (non-ASCII bytes replaced with `_`).
     *
     * @internal Not part of the public API; exposed only for SDK-internal use
     *           and direct unit testing. May change or be removed in any
     *           release without notice.
     *
     * @param string $filename the (validated) filename
     * @return string the directive string
     */
    public static function buildFilenameDirective(string $filename): string
    {
        $escaped = str_replace(['\\', '"'], ['\\\\', '\\"'], $filename);
        $isAscii = preg_match('/^[\x00-\x7F]*$/u', $filename) === 1;
        if ($isAscii) {
            return 'filename="' . $escaped . '"';
        }
        $fallback = preg_replace('/[^\x20-\x7E]/u', '_', $filename) ?? '';
        $fallbackEscaped = str_replace(['\\', '"'], ['\\\\', '\\"'], $fallback);
        $encoded = self::rfc5987EncodeValue($filename);

        return 'filename="' . $fallbackEscaped . '"; filename*=UTF-8\'\'' . $encoded;
    }

    /**
     * Percent-encodes every byte that is not an RFC 3986 §2.3 unreserved
     * character, producing the value-chars production of RFC 5987 §3.2.1.
     *
     * @param string $s the value to encode
     * @return string the percent-encoded value
     */
    private static function rfc5987EncodeValue(string $s): string
    {
        $hex = '0123456789ABCDEF';
        $bytes = unpack('C*', $s);
        if ($bytes === false) {
            return '';
        }
        $out = '';
        foreach ($bytes as $b) {
            $isUnreserved =
                ($b >= 0x41 && $b <= 0x5A) ||
                ($b >= 0x61 && $b <= 0x7A) ||
                ($b >= 0x30 && $b <= 0x39) ||
                $b === 0x2D || $b === 0x2E || $b === 0x5F || $b === 0x7E;
            if ($isUnreserved) {
                $out .= chr($b);
            } else {
                $out .= '%' . $hex[$b >> 4] . $hex[$b & 0x0F];
            }
        }

        return $out;
    }
}
